mapper.select:
SELECT supplier_id AS supplierId, COUNT(*) AS purchaseCount, COALESCE(SUM(total_amount), 0) AS totalAmount FROM oms_purchase_order WHERE enterprise_id = #{enterpriseId} AND supplier_id IN
#{id}
GROUP BY supplier_id

SELECT id, order_no AS orderNo, total_amount AS totalAmount,
       status, created_at AS createdAt
FROM oms_purchase_order
WHERE enterprise_id = #{enterpriseId}
  AND supplier_id = #{supplierId}
ORDER BY id DESC
LIMIT #{limit}

SELECT order_id AS orderId, product_name AS productName, quantity FROM oms_purchase_order_item WHERE order_id IN
#{id}
ORDER BY order_id, id
